import TableBody from './TableBody.js'
import TableHead from './TableHead.js'

/*
   компонент, выводящий на страницу таблицу с пагинацией
   пропсы:
      data - данные для таблицы в виде массива объектов
*/

const Table = (props) => {
    const currentPage = 3;
	  //количество страниц разбиения таблицы
    const n = Math.ceil(props.data.length / props.amountRows); 

    // массив с номерами страниц
    const arr = Array.from({ length: n }, (v, i) => i + 1);

    //формируем совокупность span с номерами страниц
    const pages = arr.map((item, index) =>  
          <span key={ index } className={ item === currentPage ? "page-number active" : "page-number"}>  {item} </span>
    );

    return( 
      <>
        <table>
            <TableHead head={ Object.keys(props.data[0]) } />
            <TableBody body={ props.data } amountRows={props.isPagination ?  props.amountRows : props.data.length} numPage={props.isPagination ? currentPage : "1"}/>
        </table>

        {props.isPagination ? <div>{pages}</div> : none}
	  </>   
    )   
}

export default Table;
